mylite_storage_result mylite_storage_store_schema(const char *filename, const char *schema_name) {
    if (filename == NULL || filename[0] == '\0') {
        return MYLITE_STORAGE_MISUSE;
    }

    size_t schema_name_size = 0U;
    mylite_storage_result result = validate_schema_name(schema_name, &schema_name_size);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    mylite_storage_update_file_scope file_scope = {0};
    result = open_existing_file_for_update_scope(filename, &file_scope);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    FILE *file = file_scope.file;

    mylite_storage_header header = {0};
    mylite_storage_catalog_image catalog = {0};
    result = read_header_from_update_file_scope(&file_scope, &header);
    if (result == MYLITE_STORAGE_OK) {
        result = read_catalog_image(file, &header, &catalog);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = find_schema_record(&catalog, schema_name);
        if (result == MYLITE_STORAGE_OK) {
            free_catalog_image(&catalog);
            if (close_existing_update_file_scope(&file_scope) != MYLITE_STORAGE_OK) {
                return MYLITE_STORAGE_IOERR;
            }
            return MYLITE_STORAGE_OK;
        }
        if (result == MYLITE_STORAGE_NOTFOUND) {
            const mylite_storage_schema_definition definition = {
                .size = sizeof(definition),
                .schema_name = schema_name,
            };
            const mylite_storage_schema_definition_lengths lengths = {
                .schema_name_size = schema_name_size,
            };
            result = append_schema_record(&catalog, &definition, &lengths);
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        result = begin_write_journal_preserving_durable_catalog_caches(file, filename, &header, 1);
    }
    if (result == MYLITE_STORAGE_OK) {
        result =
            publish_catalog_image_retargeting_durable_caches(file, filename, &header, &catalog);
    }
    free_catalog_image(&catalog);
    if (close_existing_update_file_scope(&file_scope) != MYLITE_STORAGE_OK &&
        result == MYLITE_STORAGE_OK) {
        result = MYLITE_STORAGE_IOERR;
    }
    return result;
}

