mylite_storage_result mylite_storage_store_index_root(
    const char *filename,
    const mylite_storage_index_root_definition *definition
) {
    if (filename == NULL || filename[0] == '\0') {
        return MYLITE_STORAGE_MISUSE;
    }

    mylite_storage_index_root_definition_lengths lengths = {0};
    mylite_storage_result result = validate_index_root_definition(definition, &lengths);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    mylite_storage_update_file_scope file_scope = {0};
    result = open_existing_file_for_update_scope(filename, &file_scope);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    FILE *file = file_scope.file;

    mylite_storage_header header = {0};
    mylite_storage_catalog_image catalog = {0};
    mylite_storage_catalog_entry table_entry = {0};
    result = read_header_from_update_file_scope(&file_scope, &header);
    if (result == MYLITE_STORAGE_OK) {
        result = read_catalog_image(file, &header, &catalog);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = find_table_record(
            &catalog,
            definition->schema_name,
            definition->table_name,
            &table_entry
        );
    }
    if (result == MYLITE_STORAGE_OK &&
        (definition->root_page == 0ULL || definition->root_page >= header.page_count)) {
        result = MYLITE_STORAGE_MISUSE;
    }
    if (result == MYLITE_STORAGE_OK) {
        result = remove_index_root_record(
            &catalog,
            definition->schema_name,
            definition->table_name,
            table_entry.table_id,
            definition->index_number
        );
        if (result == MYLITE_STORAGE_NOTFOUND) {
            result = MYLITE_STORAGE_OK;
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        result = append_index_root_record(&catalog, definition, &lengths, table_entry.table_id);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = begin_write_journal(file, filename, &header, 1);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = publish_catalog_image(file, filename, &header, &catalog);
    }
    free_catalog_image(&catalog);

    if (close_existing_update_file_scope(&file_scope) != MYLITE_STORAGE_OK &&
        result == MYLITE_STORAGE_OK) {
        result = MYLITE_STORAGE_IOERR;
    }
    return result;
}

mylite_storage_result mylite_storage_read_index_root(
    const char *filename,
    const char *schema_name,
    const char *table_name,
    unsigned index_number,
    mylite_storage_index_root_metadata *out_metadata
) {
    if (filename == NULL || filename[0] == '\0' || schema_name == NULL || schema_name[0] == '\0' ||
        table_name == NULL || table_name[0] == '\0' || out_metadata == NULL ||
        out_metadata->size < sizeof(*out_metadata)) {
        return MYLITE_STORAGE_MISUSE;
    }

    *out_metadata = (mylite_storage_index_root_metadata){
        .size = sizeof(*out_metadata),
    };

    mylite_storage_file_scope file_scope = {0};
    mylite_storage_result result = open_existing_file_scope(filename, &file_scope);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    FILE *file = file_scope.file;
    mylite_storage_statement *active_cache_statement =
        active_cache_statement_from_statement(file_scope.active_statement);
    mylite_storage_header header = {0};
    mylite_storage_catalog_image catalog = {0};
    mylite_storage_catalog_entry table_entry = {0};
    mylite_storage_catalog_entry entry = {0};
    result = read_header_from_file_scope(&file_scope, &header);
    if (result == MYLITE_STORAGE_OK) {
        result = read_catalog_image(file, &header, &catalog);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = find_table_record(&catalog, schema_name, table_name, &table_entry);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = find_index_root_record_in_statement(
            active_cache_statement,
            &header,
            &catalog,
            schema_name,
            table_name,
            table_entry.table_id,
            index_number,
            &entry
        );
    }
    unsigned long long entry_count = 0ULL;
    if (result == MYLITE_STORAGE_OK) {
        result = read_index_root_entry_count(
            file,
            &header,
            &entry,
            table_entry.table_id,
            index_number,
            &entry_count
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        *out_metadata = (mylite_storage_index_root_metadata){
            .size = sizeof(*out_metadata),
            .root_page = entry.definition_root_page,
            .entry_count = entry_count,
        };
    }

    free_catalog_image(&catalog);
    if (close_existing_file_scope(&file_scope) != MYLITE_STORAGE_OK &&
        result == MYLITE_STORAGE_OK) {
        result = MYLITE_STORAGE_IOERR;
    }
    if (result != MYLITE_STORAGE_OK) {
        *out_metadata = (mylite_storage_index_root_metadata){
            .size = sizeof(*out_metadata),
        };
    }
    return result;
}

static mylite_storage_result read_index_root_entry_count(
    FILE *file,
    const mylite_storage_header *header,
    const mylite_storage_catalog_entry *entry,
    unsigned long long table_id,
    unsigned index_number,
    unsigned long long *out_entry_count
) {
    *out_entry_count = entry->definition_size;
    if (!is_addressable_page_id(header, entry->definition_root_page)) {
        return MYLITE_STORAGE_CORRUPT;
    }

    unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_result result =
        read_page_at(file, entry->definition_root_page, header->page_size, page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (is_index_branch_page(page)) {
        mylite_storage_index_branch_page branch_page = {0};
        result = decode_index_branch_page(header, entry->definition_root_page, page, &branch_page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (branch_page.table_id != table_id || branch_page.index_number != index_number) {
            return MYLITE_STORAGE_CORRUPT;
        }
        if (branch_page.entry_count != 0ULL) {
            *out_entry_count = branch_page.entry_count;
        }
        return MYLITE_STORAGE_OK;
    }
    if (!is_maintained_index_root_page(page)) {
        return MYLITE_STORAGE_OK;
    }

    mylite_storage_maintained_index_root_page root_page = {0};
    result =
        decode_maintained_index_root_page(header, entry->definition_root_page, page, &root_page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (root_page.table_id != table_id || root_page.index_number != index_number) {
        return MYLITE_STORAGE_CORRUPT;
    }

    *out_entry_count = (unsigned long long)root_page.entry_count;
    return MYLITE_STORAGE_OK;
}

mylite_storage_result mylite_storage_drop_index_root(
    const char *filename,
    const char *schema_name,
    const char *table_name,
    unsigned index_number
) {
    if (filename == NULL || filename[0] == '\0' || schema_name == NULL || schema_name[0] == '\0' ||
        table_name == NULL || table_name[0] == '\0') {
        return MYLITE_STORAGE_MISUSE;
    }

    mylite_storage_update_file_scope file_scope = {0};
    mylite_storage_result result = open_existing_file_for_update_scope(filename, &file_scope);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    FILE *file = file_scope.file;

    mylite_storage_header header = {0};
    mylite_storage_catalog_image catalog = {0};
    mylite_storage_catalog_entry table_entry = {0};
    result = read_header_from_update_file_scope(&file_scope, &header);
    if (result == MYLITE_STORAGE_OK) {
        result = read_catalog_image(file, &header, &catalog);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = find_table_record(&catalog, schema_name, table_name, &table_entry);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = remove_index_root_record(
            &catalog,
            schema_name,
            table_name,
            table_entry.table_id,
            index_number
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        result = begin_write_journal(file, filename, &header, 1);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = publish_catalog_image(file, filename, &header, &catalog);
    }
    free_catalog_image(&catalog);

    if (close_existing_update_file_scope(&file_scope) != MYLITE_STORAGE_OK &&
        result == MYLITE_STORAGE_OK) {
        result = MYLITE_STORAGE_IOERR;
    }
    return result;
}

mylite_storage_result mylite_storage_initialize_empty_index_roots(
    const char *filename,
    const char *schema_name,
    const char *table_name,
    const mylite_storage_empty_index_root_definition *definitions,
    size_t definition_count
) {
    if (filename == NULL || filename[0] == '\0') {
        return MYLITE_STORAGE_MISUSE;
    }

    size_t schema_name_size = 0U;
    size_t table_name_size = 0U;
    mylite_storage_result result = validate_string_field(schema_name, &schema_name_size);
    if (result == MYLITE_STORAGE_OK) {
        result = validate_string_field(table_name, &table_name_size);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = validate_empty_index_root_definitions(definitions, definition_count);
    }
    if (result != MYLITE_STORAGE_OK || definition_count == 0U) {
        return result;
    }
    if (definition_count > SIZE_MAX / MYLITE_STORAGE_FORMAT_PAGE_SIZE) {
        return MYLITE_STORAGE_FULL;
    }
    unsigned char *pages =
        (unsigned char *)calloc(definition_count, MYLITE_STORAGE_FORMAT_PAGE_SIZE);
    if (pages == NULL) {
        return MYLITE_STORAGE_NOMEM;
    }

    mylite_storage_update_file_scope file_scope = {0};
    result = open_existing_file_for_update_scope(filename, &file_scope);
    if (result != MYLITE_STORAGE_OK) {
        free(pages);
        return result;
    }
    FILE *file = file_scope.file;

    mylite_storage_header header = {0};
    mylite_storage_catalog_image catalog = {0};
    mylite_storage_catalog_entry table_entry = {0};
    result = read_header_from_update_file_scope(&file_scope, &header);
    if (result == MYLITE_STORAGE_OK) {
        result = read_catalog_image(file, &header, &catalog);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = find_table_record(&catalog, schema_name, table_name, &table_entry);
    }
    if (result == MYLITE_STORAGE_OK &&
        (unsigned long long)definition_count > ULLONG_MAX - header.page_count) {
        result = MYLITE_STORAGE_FULL;
    }

    const unsigned long long first_root_page = header.page_count;
    const mylite_storage_index_root_definition_lengths lengths = {
        .schema_name_size = schema_name_size,
        .table_name_size = table_name_size,
    };
    const mylite_storage_index_entryset empty_entryset = {
        .size = sizeof(empty_entryset),
    };
    for (size_t i = 0U; result == MYLITE_STORAGE_OK && i < definition_count; ++i) {
        const mylite_storage_empty_index_root_definition *definition = definitions + i;
        result = find_index_root_record(
            &catalog,
            schema_name,
            table_name,
            table_entry.table_id,
            definition->index_number,
            NULL
        );
        if (result == MYLITE_STORAGE_OK) {
            result = MYLITE_STORAGE_MISUSE;
        } else if (result == MYLITE_STORAGE_NOTFOUND) {
            result = MYLITE_STORAGE_OK;
        }
        const unsigned long long root_page = first_root_page + (unsigned long long)i;
        if (result == MYLITE_STORAGE_OK) {
            result = encode_maintained_index_root_page_from_entryset(
                pages + (i * MYLITE_STORAGE_FORMAT_PAGE_SIZE),
                root_page,
                table_entry.table_id,
                definition->index_number,
                definition->key_size,
                &empty_entryset
            );
        }
        if (result == MYLITE_STORAGE_OK) {
            const mylite_storage_index_root_definition root_definition = {
                .size = sizeof(root_definition),
                .schema_name = schema_name,
                .table_name = table_name,
                .index_number = definition->index_number,
                .root_page = root_page,
                .entry_count = 0ULL,
            };
            result = append_index_root_record(
                &catalog,
                &root_definition,
                &lengths,
                table_entry.table_id
            );
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        result = begin_write_journal(file, filename, &header, 1);
    }
    if (result == MYLITE_STORAGE_OK) {
        const mylite_storage_pager pager = open_storage_pager(file, filename, &header);
        for (size_t i = 0U; result == MYLITE_STORAGE_OK && i < definition_count; ++i) {
            result = pager_write_page(
                &pager,
                first_root_page + (unsigned long long)i,
                pages + (i * MYLITE_STORAGE_FORMAT_PAGE_SIZE)
            );
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        header.page_count = first_root_page + (unsigned long long)definition_count;
        result = publish_catalog_image(file, filename, &header, &catalog);
    }

    free_catalog_image(&catalog);
    free(pages);
    if (close_existing_update_file_scope(&file_scope) != MYLITE_STORAGE_OK &&
        result == MYLITE_STORAGE_OK) {
        result = MYLITE_STORAGE_IOERR;
    }
    return result;
}

mylite_storage_result mylite_storage_rebuild_index_leaf(
    const char *filename,
    const char *schema_name,
    const char *table_name,
    unsigned index_number
) {
    return mylite_storage_rebuild_index_leaves(
        filename,
        schema_name,
        table_name,
        &index_number,
        1U
    );
}

mylite_storage_result mylite_storage_rebuild_index_leaves(
    const char *filename,
    const char *schema_name,
    const char *table_name,
    const unsigned *index_numbers,
    size_t index_number_count
) {
    if (filename == NULL || filename[0] == '\0' || schema_name == NULL || schema_name[0] == '\0' ||
        table_name == NULL || table_name[0] == '\0' ||
        validate_index_leaf_rebuild_numbers(index_numbers, index_number_count) !=
            MYLITE_STORAGE_OK) {
        return MYLITE_STORAGE_MISUSE;
    }

    if (index_number_count > SIZE_MAX / sizeof(mylite_storage_index_leaf_rebuild)) {
        return MYLITE_STORAGE_FULL;
    }
    mylite_storage_index_leaf_rebuild *rebuilds =
        (mylite_storage_index_leaf_rebuild *)calloc(index_number_count, sizeof(*rebuilds));
    if (rebuilds == NULL) {
        return MYLITE_STORAGE_NOMEM;
    }
    initialize_index_leaf_rebuilds(rebuilds, index_numbers, index_number_count);

    mylite_storage_update_file_scope file_scope = {0};
    mylite_storage_result result = open_existing_file_for_update_scope(filename, &file_scope);
    if (result != MYLITE_STORAGE_OK) {
        free_index_leaf_rebuilds(rebuilds, index_number_count);
        return result;
    }
    FILE *file = file_scope.file;

    mylite_storage_header header = {0};
    mylite_storage_catalog_image catalog = {0};
    mylite_storage_catalog_entry table_entry = {0};
    result = read_header_from_update_file_scope(&file_scope, &header);
    if (result == MYLITE_STORAGE_OK) {
        result = read_catalog_image(file, &header, &catalog);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = find_table_record(&catalog, schema_name, table_name, &table_entry);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = read_live_index_entrysets(
            file,
            filename,
            &header,
            &catalog,
            schema_name,
            table_name,
            table_entry.table_id,
            rebuilds,
            index_number_count
        );
    }
    unsigned long long next_page = header.page_count;
    if (result == MYLITE_STORAGE_OK) {
        result = prepare_index_leaf_rebuild_pages(
            rebuilds,
            index_number_count,
            table_entry.table_id,
            header.page_count,
            &next_page
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        result = publish_index_leaf_rebuild_roots(
            &catalog,
            schema_name,
            table_name,
            table_entry.table_id,
            rebuilds,
            index_number_count
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        result = begin_write_journal(file, filename, &header, 1);
    }
    if (result == MYLITE_STORAGE_OK) {
        const mylite_storage_pager pager = open_storage_pager(file, filename, &header);
        result = write_index_leaf_rebuild_pages(&pager, rebuilds, index_number_count);
    }
    if (result == MYLITE_STORAGE_OK) {
        header.page_count = next_page;
        result = publish_catalog_image(file, filename, &header, &catalog);
    }

    free_catalog_image(&catalog);
    free_index_leaf_rebuilds(rebuilds, index_number_count);
    if (close_existing_update_file_scope(&file_scope) != MYLITE_STORAGE_OK &&
        result == MYLITE_STORAGE_OK) {
        result = MYLITE_STORAGE_IOERR;
    }
    return result;
}

mylite_storage_result mylite_storage_drop_table(
    const char *filename,
    const char *schema_name,
    const char *table_name
) {
    if (filename == NULL || filename[0] == '\0' || schema_name == NULL || schema_name[0] == '\0' ||
        table_name == NULL || table_name[0] == '\0') {
        return MYLITE_STORAGE_MISUSE;
    }

    mylite_storage_update_file_scope file_scope = {0};
    mylite_storage_result result = open_existing_file_for_update_scope(filename, &file_scope);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    FILE *file = file_scope.file;

    mylite_storage_header header = {0};
    mylite_storage_catalog_image catalog = {0};
    mylite_storage_catalog_entry table_entry = {0};
    result = read_header_from_update_file_scope(&file_scope, &header);
    if (result == MYLITE_STORAGE_OK) {
        result = read_catalog_image(file, &header, &catalog);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = find_table_record(&catalog, schema_name, table_name, &table_entry);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = remove_child_foreign_key_records(&catalog, schema_name, table_name);
        if (result == MYLITE_STORAGE_NOTFOUND) {
            result = MYLITE_STORAGE_OK;
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        result = find_parent_foreign_key_record(&catalog, schema_name, table_name);
        if (result == MYLITE_STORAGE_OK) {
            result = MYLITE_STORAGE_ERROR;
        } else if (result == MYLITE_STORAGE_NOTFOUND) {
            result = MYLITE_STORAGE_OK;
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        result = remove_table_index_root_records(
            &catalog,
            schema_name,
            table_name,
            table_entry.table_id
        );
        if (result == MYLITE_STORAGE_NOTFOUND) {
            result = MYLITE_STORAGE_OK;
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        result = remove_table_record(&catalog, schema_name, table_name);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = begin_write_journal(file, filename, &header, 1);
    }
    if (result == MYLITE_STORAGE_OK) {
        result = publish_catalog_image(file, filename, &header, &catalog);
    }
    free_catalog_image(&catalog);

    if (close_existing_update_file_scope(&file_scope) != MYLITE_STORAGE_OK &&
        result == MYLITE_STORAGE_OK) {
        result = MYLITE_STORAGE_IOERR;
    }
    return result;
}

