mylite_storage_result mylite_storage_begin_statement(
    const char *filename,
    mylite_storage_statement **out_statement
) {
    return begin_checkpoint(filename, out_statement, 0);
}

mylite_storage_result mylite_storage_begin_nested_statement(
    mylite_storage_statement *parent,
    mylite_storage_statement **out_statement
) {
    if (parent == NULL || out_statement == NULL) {
        return MYLITE_STORAGE_MISUSE;
    }
    *out_statement = NULL;
    if (active_statement != parent || parent->owner != active_context_owner) {
        return MYLITE_STORAGE_MISUSE;
    }

    mylite_storage_statement *statement = allocate_checkpoint_statement(parent);
    if (statement == NULL) {
        return MYLITE_STORAGE_NOMEM;
    }
    statement->filename = parent->filename;
    statement->owns_filename = 0;
    statement->owner = active_context_owner;
    inherit_statement_filename_identity(statement, parent);

    mylite_storage_result result =
        initialize_checkpoint_statement(statement, parent->filename, parent);
    if (result != MYLITE_STORAGE_OK) {
        free_statement(statement);
        return result;
    }

    active_statement = statement;
    *out_statement = statement;
    return MYLITE_STORAGE_OK;
}

mylite_storage_result mylite_storage_begin_transaction(
    const char *filename,
    mylite_storage_statement **out_statement
) {
    return begin_checkpoint(filename, out_statement, 1);
}

mylite_storage_result mylite_storage_begin_read_statement(
    const char *filename,
    mylite_storage_statement **out_statement
) {
    if (filename == NULL || filename[0] == '\0' || out_statement == NULL) {
        return MYLITE_STORAGE_MISUSE;
    }
    *out_statement = NULL;

    if (active_statement_for(filename) != NULL) {
        return MYLITE_STORAGE_OK;
    }

    mylite_storage_statement *same_file_parent = active_read_statement_for(filename);
    mylite_storage_statement *statement = allocate_read_statement();
    if (statement == NULL) {
        return MYLITE_STORAGE_NOMEM;
    }

    mylite_storage_result result = assign_read_statement_filename(statement, filename);
    if (result != MYLITE_STORAGE_OK) {
        free(statement);
        return result;
    }
    statement->reuse_read_statement_storage = 1;
    statement->owner = active_context_owner;
    statement->parent = active_read_statement;

    result = initialize_read_statement(statement, filename, same_file_parent);
    if (result != MYLITE_STORAGE_OK) {
        free_statement(statement);
        return result;
    }

    active_read_statement = statement;
    *out_statement = statement;
    return MYLITE_STORAGE_OK;
}

int mylite_storage_statement_active(const char *filename) {
    return active_statement_for(filename) != NULL ? 1 : 0;
}

mylite_storage_statement *mylite_storage_borrow_active_statement(const char *filename) {
    return active_statement_for(filename);
}

int mylite_storage_statement_matches(mylite_storage_statement *statement, const char *filename) {
    if (statement == NULL || statement->filename == NULL || filename == NULL) {
        return 0;
    }
    return active_statement_filename_matches(statement, filename) ? 1 : 0;
}

int mylite_storage_context_has_active_statement(void) {
    return active_context_owner != NULL && active_statement != NULL &&
                   active_statement->owner == active_context_owner
               ? 1
               : 0;
}

int mylite_storage_context_has_active_read_statement(const char *filename) {
    return active_context_owner != NULL && active_read_statement_for(filename) != NULL ? 1 : 0;
}

mylite_storage_result mylite_storage_preserve_auto_increment_on_rollback(const char *filename) {
    if (filename == NULL || filename[0] == '\0') {
        return MYLITE_STORAGE_MISUSE;
    }

    mylite_storage_statement *statement = active_statement_for(filename);
    if (statement == NULL) {
        return MYLITE_STORAGE_OK;
    }

    statement->preserve_auto_increment_rollback = 1;
    return MYLITE_STORAGE_OK;
}

const void *mylite_storage_context_owner(void) {
    return active_context_owner;
}

void mylite_storage_set_context_owner(const void *owner) {
    active_context_owner = owner;
}

void mylite_storage_clear_thread_caches(void) {
    clear_read_checkpoint_cache();
    clear_cached_read_file(NULL);
    clear_journal_path_cache(NULL);
    clear_durable_live_row_id_caches(NULL);
    clear_durable_row_payload_caches(NULL);
    clear_durable_index_leaf_page_caches(NULL);
    clear_durable_exact_index_caches(NULL);
    free_reusable_statement(&reusable_read_statement);
    free_reusable_statement(&reusable_nested_checkpoint_statement);
}

