mylite_storage_result mylite_storage_test_protect_active_dirty_pages(
    const char *filename,
    const unsigned long long *page_ids,
    size_t page_count
) {
    if (filename == NULL || filename[0] == '\0' || page_ids == NULL || page_count == 0U ||
        page_count > MYLITE_STORAGE_FORMAT_JOURNAL_MAX_PROTECTED_PAGES) {
        return MYLITE_STORAGE_MISUSE;
    }
    if (active_statement_for(filename) == NULL) {
        return MYLITE_STORAGE_MISUSE;
    }

    mylite_storage_update_file_scope scope = {0};
    mylite_storage_result result = open_existing_file_for_update_scope(filename, &scope);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    mylite_storage_header header = {0};
    result = read_header_from_update_file_scope(&scope, &header);
    for (size_t i = 0U; result == MYLITE_STORAGE_OK && i < page_count; ++i) {
        if (page_ids[i] == MYLITE_STORAGE_FORMAT_HEADER_PAGE_ID ||
            page_ids[i] >= header.page_count) {
            result = MYLITE_STORAGE_MISUSE;
        }
    }
    if (result == MYLITE_STORAGE_OK) {
        result = begin_write_journal_for_statement_pages(
            scope.file,
            filename,
            &header,
            0,
            scope.active_statement,
            page_ids,
            page_count
        );
    }
    if (close_existing_update_file_scope(&scope) != MYLITE_STORAGE_OK &&
        result == MYLITE_STORAGE_OK) {
        result = MYLITE_STORAGE_IOERR;
    }
    return result;
}

static unsigned long long test_checksum_page_site_family_count_by_name(
    const char *site_name,
    mylite_storage_test_checksum_page_family family
) {
    if (site_name == NULL || family >= MYLITE_STORAGE_TEST_CHECKSUM_PAGE_FAMILY_COUNT) {
        return 0ULL;
    }
    for (size_t i = 0U; i < mylite_storage_test_checksum_page_site_slot_count(); ++i) {
        const char *const slot_name = mylite_storage_test_checksum_page_site_slot_name(i);
        if (slot_name != NULL && strcmp(slot_name, site_name) == 0) {
            return mylite_storage_test_checksum_page_site_family_count(i, family);
        }
    }
    return 0ULL;
}

int mylite_storage_test_recovery_journal_snapshot_reuses_validated_pages(void) {
    static const unsigned char definition[] = {0x01U, 'f', 'r', 'm', 0x00U};
    static const unsigned char row_1[] = {0x00U, 0x01U, 'o', 'n', 'e'};
    static const unsigned char row_2[] = {0x00U, 0x02U, 't', 'w', 'o'};
    static const unsigned char row_3[] = {0x00U, 0x03U, 't', 'h', 'r'};
    char filename[] = "/tmp/mylite-journal-snapshot-XXXXXX";
    int fd = mkstemp(filename);
    if (fd < 0) {
        return 0;
    }
    close(fd);
    unlink(filename);

    char *journal_filename = recovery_journal_path(filename);
    if (journal_filename == NULL) {
        return 0;
    }

    mylite_storage_table_definition table_definition = {
        .size = sizeof(table_definition),
        .schema_name = "app",
        .table_name = "posts",
        .requested_engine_name = "MYLITE",
        .effective_engine_name = "MYLITE",
        .definition = definition,
        .definition_size = sizeof(definition),
    };
    mylite_storage_rowset rows = {
        .size = sizeof(rows),
    };
    mylite_storage_statement *statement = NULL;
    unsigned long long row_1_id = 0ULL;
    unsigned long long row_2_id = 0ULL;
    int ok = 0;

    if (mylite_storage_create_empty(filename) != MYLITE_STORAGE_OK ||
        mylite_storage_store_table_definition(filename, &table_definition) != MYLITE_STORAGE_OK ||
        mylite_storage_append_row_with_index_entries(
            filename,
            "app",
            "posts",
            row_1,
            sizeof(row_1),
            NULL,
            0U,
            &row_1_id
        ) != MYLITE_STORAGE_OK ||
        mylite_storage_append_row_with_index_entries(
            filename,
            "app",
            "posts",
            row_2,
            sizeof(row_2),
            NULL,
            0U,
            &row_2_id
        ) != MYLITE_STORAGE_OK) {
        goto cleanup;
    }

    if (mylite_storage_begin_statement(filename, &statement) != MYLITE_STORAGE_OK ||
        mylite_storage_append_row(filename, "app", "posts", row_3, sizeof(row_3)) !=
            MYLITE_STORAGE_OK ||
        access(journal_filename, F_OK) != 0) {
        goto cleanup;
    }

    mylite_storage_test_reset_prepared_insert_profile_counts();
    test_count_checksum_page_calls = 1;
    if (mylite_storage_test_flip_active_page_byte(
            filename,
            row_1_id,
            MYLITE_STORAGE_FORMAT_ROW_PAYLOAD_OFFSET
        ) != MYLITE_STORAGE_OK ||
        test_checksum_page_site_family_count_by_name(
            "decode_recovery_journal_header",
            MYLITE_STORAGE_TEST_CHECKSUM_PAGE_FAMILY_JOURNAL
        ) != 0ULL) {
        goto cleanup;
    }

    mylite_storage_test_reset_prepared_insert_profile_counts();
    test_count_checksum_page_calls = 1;
    if (mylite_storage_test_flip_active_page_byte(
            filename,
            row_2_id,
            MYLITE_STORAGE_FORMAT_ROW_PAYLOAD_OFFSET
        ) != MYLITE_STORAGE_OK ||
        test_checksum_page_site_family_count_by_name(
            "decode_recovery_journal_header",
            MYLITE_STORAGE_TEST_CHECKSUM_PAGE_FAMILY_JOURNAL
        ) != 0ULL) {
        goto cleanup;
    }

    if (mylite_storage_rollback_statement(statement) != MYLITE_STORAGE_OK) {
        statement = NULL;
        goto cleanup;
    }
    statement = NULL;
    if (access(journal_filename, F_OK) == 0 ||
        mylite_storage_read_rows(filename, "app", "posts", &rows) != MYLITE_STORAGE_OK ||
        rows.row_count != 2U || rows.row_size != sizeof(row_1) ||
        memcmp(rows.rows + rows.row_offsets[0], row_1, sizeof(row_1)) != 0 ||
        memcmp(rows.rows + rows.row_offsets[1], row_2, sizeof(row_2)) != 0) {
        goto cleanup;
    }
    ok = 1;

cleanup:
    mylite_storage_free_rowset(&rows);
    if (statement != NULL) {
        (void)mylite_storage_rollback_statement(statement);
    }
    remove(journal_filename);
    remove(filename);
    free(journal_filename);
    test_count_checksum_page_calls = 0;
    mylite_storage_test_reset_prepared_insert_profile_counts();
    return ok;
}

int mylite_storage_test_checksum_page_family_counters(void) {
    unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    int ok = 1;

    mylite_storage_test_reset_prepared_insert_profile_counts();

    memset(page, 0, sizeof(page));
    memcpy(page, k_header_magic, sizeof(k_header_magic));
    (void)checksum_page(page, MYLITE_STORAGE_FORMAT_HEADER_CHECKSUM_OFFSET);

    memset(page, 0, sizeof(page));
    put_u32_le(
        page,
        MYLITE_STORAGE_FORMAT_INDEX_PAGE_TYPE_OFFSET,
        MYLITE_STORAGE_FORMAT_INDEX_PAGE_TYPE_TABLE_INDEX_LEAF
    );
    (void)checksum_page_zero_tail(
        page,
        MYLITE_STORAGE_FORMAT_INDEX_LEAF_CHECKSUM_OFFSET,
        MYLITE_STORAGE_FORMAT_INDEX_LEAF_PAYLOAD_OFFSET
    );

    memset(page, 0, sizeof(page));
    put_u32_le(
        page,
        MYLITE_STORAGE_FORMAT_INDEX_PAGE_TYPE_OFFSET,
        MYLITE_STORAGE_FORMAT_INDEX_PAGE_TYPE_TABLE_INDEX_BRANCH
    );
    (void)checksum_page(page, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CHECKSUM_OFFSET);

    memset(page, 0, sizeof(page));
    (void)checksum_page(page, MYLITE_STORAGE_FORMAT_INDEX_LEAF_CHECKSUM_OFFSET);

    const char *const site_name = mylite_storage_test_checksum_page_site_slot_name(0U);
    ok =
        test_checksum_page_count == 3ULL && test_checksum_page_zero_tail_count == 1ULL &&
        test_checksum_page_family_counts[MYLITE_STORAGE_TEST_CHECKSUM_PAGE_FAMILY_HEADER] == 1ULL &&
        test_checksum_page_family_counts[MYLITE_STORAGE_TEST_CHECKSUM_PAGE_FAMILY_INDEX_BRANCH] ==
            1ULL &&
        test_checksum_page_family_counts[MYLITE_STORAGE_TEST_CHECKSUM_PAGE_FAMILY_UNKNOWN] ==
            1ULL &&
        test_checksum_page_zero_tail_family_counts
                [MYLITE_STORAGE_TEST_CHECKSUM_PAGE_FAMILY_INDEX_LEAF] == 1ULL &&
        strcmp(
            test_checksum_page_family_names[MYLITE_STORAGE_TEST_CHECKSUM_PAGE_FAMILY_INDEX_LEAF],
            "index-leaf"
        ) == 0 &&
        mylite_storage_test_checksum_page_site_slot_count() == 1U && site_name != NULL &&
        strcmp(site_name, "mylite_storage_test_checksum_page_family_counters") == 0 &&
        mylite_storage_test_checksum_page_site_family_count(
            0U,
            MYLITE_STORAGE_TEST_CHECKSUM_PAGE_FAMILY_HEADER
        ) == 1ULL &&
        mylite_storage_test_checksum_page_site_family_count(
            0U,
            MYLITE_STORAGE_TEST_CHECKSUM_PAGE_FAMILY_INDEX_BRANCH
        ) == 1ULL &&
        mylite_storage_test_checksum_page_site_family_count(
            0U,
            MYLITE_STORAGE_TEST_CHECKSUM_PAGE_FAMILY_UNKNOWN
        ) == 1ULL &&
        mylite_storage_test_checksum_page_zero_tail_site_family_count(
            0U,
            MYLITE_STORAGE_TEST_CHECKSUM_PAGE_FAMILY_INDEX_LEAF
        ) == 1ULL &&
        mylite_storage_test_checksum_page_site_slot_name(1U) == NULL &&
        mylite_storage_test_checksum_page_site_family_count(
            1U,
            MYLITE_STORAGE_TEST_CHECKSUM_PAGE_FAMILY_HEADER
        ) == 0ULL &&
        mylite_storage_test_checksum_page_zero_tail_site_family_count(
            0U,
            MYLITE_STORAGE_TEST_CHECKSUM_PAGE_FAMILY_COUNT
        ) == 0ULL;

    mylite_storage_test_reset_prepared_insert_profile_counts();
    ok = ok && mylite_storage_test_checksum_page_site_slot_count() == 0U &&
         mylite_storage_test_checksum_page_site_slot_name(0U) == NULL &&
         mylite_storage_test_checksum_page_site_family_count(
             0U,
             MYLITE_STORAGE_TEST_CHECKSUM_PAGE_FAMILY_HEADER
         ) == 0ULL;
    test_count_checksum_page_calls = 0;
    return ok;
}

