int mylite_storage_test_branch_leaf_split_branch_encode_validation(void) {
    enum { key_size = 1U };

    unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE] = {0};
    const unsigned long long child_page_ids[] = {30ULL, 60ULL, 31ULL};
    const unsigned long long child_max_row_ids[] = {10ULL, 20ULL, 30ULL};
    const unsigned char child_max_keys[] = {0x10U, 0x20U, 0x30U};
    const unsigned long long bad_child_page_ids[] = {30ULL, 40ULL, 31ULL};
    const unsigned long long unordered_child_max_row_ids[] = {10ULL, 10ULL, 30ULL};
    const unsigned char unordered_child_max_keys[] = {0x10U, 0x10U, 0x30U};
    mylite_storage_header header = {
        .size = sizeof(header),
        .format_version = MYLITE_STORAGE_FORMAT_VERSION,
        .header_version = MYLITE_STORAGE_FORMAT_HEADER_VERSION,
        .page_size = MYLITE_STORAGE_FORMAT_PAGE_SIZE,
        .page_count = 61ULL,
    };
    mylite_storage_index_branch_page branch_page = {0};

    mylite_storage_test_reset_prepared_insert_profile_counts();
    mylite_storage_result result = validate_index_branch_encode_components(
        &header,
        40ULL,
        1U,
        key_size,
        3ULL,
        child_page_ids,
        child_max_row_ids,
        child_max_keys,
        3U
    );
    if (result == MYLITE_STORAGE_OK) {
        result = encode_index_branch_page(
            page,
            40ULL,
            9ULL,
            3U,
            1U,
            key_size,
            3ULL,
            child_page_ids,
            child_max_row_ids,
            child_max_keys,
            3U
        );
    }

    int ok = result == MYLITE_STORAGE_OK && mylite_storage_test_checksum_page_count() == 0ULL &&
             mylite_storage_test_checksum_page_zero_tail_count() == 1ULL &&
             mylite_storage_test_index_branch_decode_site_slot_count() == 0U &&
             decode_index_branch_page(&header, 40ULL, page, &branch_page) == MYLITE_STORAGE_OK &&
             branch_page.child_count == 3U;

    mylite_storage_test_reset_prepared_insert_profile_counts();
    result = validate_index_branch_encode_components(
        &header,
        40ULL,
        1U,
        key_size,
        3ULL,
        child_page_ids,
        child_max_row_ids,
        child_max_keys,
        3U
    );
    if (result == MYLITE_STORAGE_OK) {
        result = encode_index_branch_page_without_checksum(
            page,
            40ULL,
            9ULL,
            3U,
            1U,
            key_size,
            3ULL,
            child_page_ids,
            child_max_row_ids,
            child_max_keys,
            3U
        );
    }
    ok = ok && result == MYLITE_STORAGE_OK &&
         mylite_storage_test_checksum_page_zero_tail_count() == 0ULL &&
         get_u64_le(page, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CHECKSUM_OFFSET) == 0ULL;
    if (ok) {
        result = refresh_dirty_buffered_page_checksum(
            page,
            MYLITE_STORAGE_DIRTY_CHECKSUM_REFRESH_SOURCE_TEST_HOOK
        );
        ok = result == MYLITE_STORAGE_OK &&
             mylite_storage_test_checksum_page_zero_tail_count() == 1ULL &&
             mylite_storage_test_dirty_checksum_refresh_source_family_count(
                 MYLITE_STORAGE_DIRTY_CHECKSUM_REFRESH_SOURCE_TEST_HOOK,
                 MYLITE_STORAGE_TEST_CHECKSUM_PAGE_FAMILY_INDEX_BRANCH
             ) == 1ULL;
    }
    test_count_checksum_page_calls = 0;
    ok = ok && decode_index_branch_page(&header, 40ULL, page, &branch_page) == MYLITE_STORAGE_OK &&
         branch_page.child_count == 3U;
    mylite_storage_test_reset_prepared_insert_profile_counts();

    mylite_storage_header stale_header = header;
    stale_header.page_count = 60ULL;
    ok = ok && validate_index_branch_encode_components(
                   &stale_header,
                   40ULL,
                   1U,
                   key_size,
                   3ULL,
                   child_page_ids,
                   child_max_row_ids,
                   child_max_keys,
                   3U
               ) == MYLITE_STORAGE_CORRUPT;
    ok = ok && validate_index_branch_encode_components(
                   &header,
                   40ULL,
                   1U,
                   key_size,
                   3ULL,
                   bad_child_page_ids,
                   child_max_row_ids,
                   child_max_keys,
                   3U
               ) == MYLITE_STORAGE_CORRUPT;
    ok = ok && validate_index_branch_encode_components(
                   &header,
                   40ULL,
                   1U,
                   key_size,
                   3ULL,
                   child_page_ids,
                   unordered_child_max_row_ids,
                   unordered_child_max_keys,
                   3U
               ) == MYLITE_STORAGE_CORRUPT;

    test_count_checksum_page_calls = 0;
    return ok;
}

