static mylite_storage_result read_limited_index_leaf_entries_from_prefix(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    mylite_storage_statement *active_cache_statement,
    const mylite_storage_catalog_image *catalog,
    unsigned long long table_id,
    const char *schema_name,
    const char *table_name,
    unsigned index_number,
    const unsigned char *key_prefix,
    size_t key_prefix_size,
    const unsigned char *after_key,
    size_t after_key_size,
    unsigned long long after_row_id,
    size_t max_entry_count,
    mylite_storage_index_entryset *out_entries,
    unsigned long long *out_tail_page_id,
    int *out_complete
) {
    *out_complete = 1;
    *out_tail_page_id = header->page_count;

    mylite_storage_catalog_entry root_entry = {0};
    mylite_storage_result result = find_index_root_record_in_statement(
        active_cache_statement,
        header,
        catalog,
        schema_name,
        table_name,
        table_id,
        index_number,
        &root_entry
    );
    if (result == MYLITE_STORAGE_NOTFOUND) {
        return MYLITE_STORAGE_UNSUPPORTED;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    const mylite_storage_pager pager = open_storage_pager(file, filename, header);
    result = pager_read_page(&pager, root_entry.definition_root_page, page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (is_index_branch_page(page)) {
        mylite_storage_index_branch_page branch_page = {0};
        result =
            decode_index_branch_page(header, root_entry.definition_root_page, page, &branch_page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }

        unsigned long long max_page_id = root_entry.definition_root_page;
        result = find_index_branch_max_page_id(
            file,
            filename,
            header,
            root_entry.definition_root_page,
            &branch_page,
            table_id,
            index_number,
            &max_page_id
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (max_page_id == ULLONG_MAX || max_page_id >= header->page_count) {
            return MYLITE_STORAGE_CORRUPT;
        }
        size_t static_entry_limit = max_entry_count;
        if (max_page_id + 1ULL < header->page_count) {
            *out_tail_page_id = max_page_id + 1ULL;
            const unsigned long long tail_page_span = header->page_count - *out_tail_page_id;
            if (tail_page_span > (unsigned long long)(SIZE_MAX - static_entry_limit)) {
                return MYLITE_STORAGE_FULL;
            }
            static_entry_limit += (size_t)tail_page_span;
        }

        if (key_prefix_size > branch_page.key_size) {
            return MYLITE_STORAGE_OK;
        }
        if (after_key != NULL && after_key_size != branch_page.key_size) {
            return MYLITE_STORAGE_MISUSE;
        }
        const unsigned char *search_key = key_prefix;
        size_t search_key_size = key_prefix_size;
        if (after_key != NULL && memcmp(after_key, key_prefix, key_prefix_size) >= 0) {
            search_key = after_key;
            search_key_size = after_key_size;
        }

        unsigned char previous_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        mylite_storage_index_leaf_page previous_page = {0};
        int has_previous_page = 0;
        return append_limited_index_branch_entries_from_prefix_to_entryset(
            file,
            filename,
            header,
            &branch_page,
            table_id,
            index_number,
            search_key,
            search_key_size,
            after_key,
            after_key_size,
            after_row_id,
            static_entry_limit,
            out_entries,
            previous_page_bytes,
            &previous_page,
            &has_previous_page,
            out_complete
        );
    }

    mylite_storage_index_leaf_page leaf_page = {0};
    mylite_storage_index_leaf_run leaf_run = {0};
    result = read_index_leaf_run_root(
        file,
        filename,
        header,
        &root_entry,
        table_id,
        index_number,
        page,
        &leaf_page,
        &leaf_run
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    size_t static_entry_limit = max_entry_count;
    if (leaf_run.tail_page_id < header->page_count) {
        *out_tail_page_id = leaf_run.tail_page_id;
        const unsigned long long tail_page_span = header->page_count - leaf_run.tail_page_id;
        if (tail_page_span > (unsigned long long)(SIZE_MAX - static_entry_limit)) {
            free_index_leaf_run(&leaf_run);
            return MYLITE_STORAGE_FULL;
        }
        static_entry_limit += (size_t)tail_page_span;
    }

    if (key_prefix_size > leaf_run.key_size) {
        free_index_leaf_run(&leaf_run);
        return MYLITE_STORAGE_OK;
    }
    if (after_key != NULL && after_key_size != leaf_run.key_size) {
        free_index_leaf_run(&leaf_run);
        return MYLITE_STORAGE_MISUSE;
    }
    const unsigned char *search_key = key_prefix;
    size_t search_key_size = key_prefix_size;
    if (after_key != NULL && memcmp(after_key, key_prefix, key_prefix_size) >= 0) {
        search_key = after_key;
        search_key_size = after_key_size;
    }

    result = append_limited_index_leaf_run_entries_from_prefix_to_entryset(
        file,
        filename,
        header,
        &leaf_run,
        page,
        &leaf_page,
        table_id,
        index_number,
        search_key,
        search_key_size,
        after_key,
        after_key_size,
        after_row_id,
        static_entry_limit,
        out_entries,
        out_complete
    );
    free_index_leaf_run(&leaf_run);
    return result;
}

static mylite_storage_result apply_limited_index_tail_overlay(
    FILE *file,
    const mylite_storage_header *header,
    unsigned long long table_id,
    unsigned index_number,
    const unsigned char *key_prefix,
    size_t key_prefix_size,
    const unsigned char *after_key,
    size_t after_key_size,
    unsigned long long after_row_id,
    size_t max_entry_count,
    unsigned long long tail_page_id,
    int static_complete,
    mylite_storage_index_entryset *inout_entries,
    int *out_complete
) {
    mylite_storage_result result = read_live_index_entries_from_lower_bound(
        file,
        header,
        table_id,
        index_number,
        key_prefix,
        key_prefix_size,
        after_key,
        after_key_size,
        after_row_id,
        tail_page_id,
        inout_entries
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    mylite_storage_index_entryset limited_entries = {
        .size = sizeof(limited_entries),
    };
    result = build_ordered_limited_index_entryset(
        inout_entries,
        key_prefix,
        key_prefix_size,
        after_key,
        after_key_size,
        after_row_id,
        max_entry_count,
        static_complete,
        &limited_entries,
        out_complete
    );
    if (result != MYLITE_STORAGE_OK) {
        mylite_storage_free_index_entryset(&limited_entries);
        return result;
    }

    mylite_storage_free_index_entryset(inout_entries);
    *inout_entries = limited_entries;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result build_ordered_limited_index_entryset(
    const mylite_storage_index_entryset *source_entries,
    const unsigned char *key_prefix,
    size_t key_prefix_size,
    const unsigned char *after_key,
    size_t after_key_size,
    unsigned long long after_row_id,
    size_t max_entry_count,
    int static_complete,
    mylite_storage_index_entryset *out_entries,
    int *out_complete
) {
    *out_entries = (mylite_storage_index_entryset){
        .size = sizeof(*out_entries),
    };
    *out_complete = static_complete ? 1 : 0;
    if (source_entries->entry_count == 0U) {
        return MYLITE_STORAGE_OK;
    }

    size_t key_size = 0U;
    mylite_storage_result result = index_entryset_fixed_key_size(source_entries, &key_size);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (after_key != NULL && after_key_size != key_size) {
        return MYLITE_STORAGE_CORRUPT;
    }

    size_t *order = NULL;
    result = build_raw_index_entry_order(source_entries, &order);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    size_t copied_entry_count = 0U;
    for (size_t i = 0U; i < source_entries->entry_count; ++i) {
        const size_t source_index = order[i];
        const unsigned char *entry_key =
            source_entries->keys + source_entries->key_offsets[source_index];
        const unsigned long long row_id = source_entries->row_ids[source_index];
        if (key_prefix_size > key_size || memcmp(entry_key, key_prefix, key_prefix_size) < 0) {
            continue;
        }
        if (after_key != NULL) {
            const int cmp = memcmp(entry_key, after_key, key_size);
            if (cmp < 0 || (cmp == 0 && row_id <= after_row_id)) {
                continue;
            }
        }
        if (copied_entry_count >= max_entry_count) {
            *out_complete = 0;
            break;
        }
        result = append_index_entryset_entry_to_entryset(out_entries, source_entries, source_index);
        if (result != MYLITE_STORAGE_OK) {
            free(order);
            return result;
        }
        ++copied_entry_count;
    }

    free(order);
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_index_entryset_entry_to_entryset(
    mylite_storage_index_entryset *target_entries,
    const mylite_storage_index_entryset *source_entries,
    size_t source_index
) {
    if (source_index >= source_entries->entry_count || source_entries->keys == NULL ||
        source_entries->key_offsets == NULL || source_entries->key_sizes == NULL ||
        source_entries->row_ids == NULL ||
        source_entries->key_offsets[source_index] > source_entries->key_bytes ||
        source_entries->key_sizes[source_index] >
            source_entries->key_bytes - source_entries->key_offsets[source_index]) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t key_size = source_entries->key_sizes[source_index];
    size_t target_index = 0U;
    size_t target_key_offset = 0U;
    mylite_storage_result result = grow_index_entryset_for_append(
        target_entries,
        1U,
        key_size,
        &target_index,
        &target_key_offset
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    memcpy(
        target_entries->keys + target_key_offset,
        source_entries->keys + source_entries->key_offsets[source_index],
        key_size
    );
    target_entries->key_offsets[target_index] = target_key_offset;
    target_entries->key_sizes[target_index] = key_size;
    target_entries->row_ids[target_index] = source_entries->row_ids[source_index];
    target_entries->entry_count = target_index + 1U;
    target_entries->key_bytes = target_key_offset + key_size;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result read_index_branch_prefix_entries(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    unsigned long long root_page_id,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned index_number,
    const unsigned char *key_prefix,
    size_t key_prefix_size,
    mylite_storage_index_entryset *out_entries,
    int *out_used_leaf
) {
    unsigned long long max_page_id = root_page_id;
    mylite_storage_result result = find_index_branch_max_page_id(
        file,
        filename,
        header,
        root_page_id,
        branch_page,
        table_id,
        index_number,
        &max_page_id
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (max_page_id == ULLONG_MAX || max_page_id >= header->page_count) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (max_page_id + 1ULL < header->page_count) {
        return MYLITE_STORAGE_OK;
    }

    *out_used_leaf = 1;
    if (key_prefix_size > branch_page->key_size) {
        return MYLITE_STORAGE_OK;
    }

    int past_prefix = 0;
    return append_index_branch_prefix_matches_to_entryset(
        file,
        filename,
        header,
        branch_page,
        table_id,
        index_number,
        key_prefix,
        key_prefix_size,
        out_entries,
        &past_prefix
    );
}

static mylite_storage_result read_index_branch_entries_from_prefix(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    unsigned long long root_page_id,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned index_number,
    const unsigned char *key_prefix,
    size_t key_prefix_size,
    mylite_storage_index_entryset *out_entries,
    int *out_used_leaf
) {
    unsigned long long max_page_id = root_page_id;
    mylite_storage_result result = find_index_branch_max_page_id(
        file,
        filename,
        header,
        root_page_id,
        branch_page,
        table_id,
        index_number,
        &max_page_id
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (max_page_id == ULLONG_MAX || max_page_id >= header->page_count) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (max_page_id + 1ULL < header->page_count) {
        return MYLITE_STORAGE_OK;
    }

    *out_used_leaf = 1;
    if (key_prefix_size > branch_page->key_size) {
        return MYLITE_STORAGE_OK;
    }

    unsigned char previous_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_index_leaf_page previous_page = {0};
    int has_previous_page = 0;
    unsigned long long appended_count = 0ULL;
    return append_index_branch_entries_from_prefix_to_entryset(
        file,
        filename,
        header,
        branch_page,
        table_id,
        index_number,
        key_prefix,
        key_prefix_size,
        out_entries,
        &appended_count,
        previous_page_bytes,
        &previous_page,
        &has_previous_page
    );
}

static mylite_storage_result append_index_branch_prefix_matches_to_entryset(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned index_number,
    const unsigned char *key_prefix,
    size_t key_prefix_size,
    mylite_storage_index_entryset *out_entries,
    int *out_past_prefix
) {
    *out_past_prefix = 0;
    if (branch_page->table_id != table_id || branch_page->index_number != index_number) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (key_prefix_size > branch_page->key_size) {
        *out_past_prefix = 1;
        return MYLITE_STORAGE_OK;
    }

    unsigned long long first_child_page_id = 0ULL;
    mylite_storage_result result = find_index_branch_prefix_child_page(
        branch_page,
        key_prefix,
        key_prefix_size,
        &first_child_page_id
    );
    if (result == MYLITE_STORAGE_NOTFOUND) {
        *out_past_prefix = 1;
        return MYLITE_STORAGE_OK;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    size_t first_child_index = 0U;
    result = find_index_branch_child_offset(branch_page, first_child_page_id, &first_child_index);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    const size_t cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
    for (size_t i = first_child_index; i < branch_page->child_count; ++i) {
        const unsigned char *cell = branch_page->payload + (i * cell_size);
        const unsigned long long child_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        if (branch_page->level == 1U) {
            result = append_index_branch_prefix_leaf_matches_to_entryset(
                file,
                filename,
                header,
                child_page_id,
                table_id,
                index_number,
                branch_page->key_size,
                key_prefix,
                key_prefix_size,
                out_entries,
                out_past_prefix
            );
        } else {
            unsigned char child_page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
            mylite_storage_index_branch_page child_branch_page = {0};
            result = read_index_branch_child_page(
                file,
                filename,
                header,
                child_page_id,
                branch_page,
                table_id,
                index_number,
                &child_branch_page,
                child_page
            );
            if (result == MYLITE_STORAGE_OK) {
                result =
                    validate_index_branch_child_branch_fence(branch_page, i, &child_branch_page);
            }
            if (result == MYLITE_STORAGE_OK) {
                result = append_index_branch_prefix_matches_to_entryset(
                    file,
                    filename,
                    header,
                    &child_branch_page,
                    table_id,
                    index_number,
                    key_prefix,
                    key_prefix_size,
                    out_entries,
                    out_past_prefix
                );
            }
        }
        if (result != MYLITE_STORAGE_OK || *out_past_prefix) {
            return result;
        }
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_index_branch_entries_from_prefix_to_entryset(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned index_number,
    const unsigned char *key_prefix,
    size_t key_prefix_size,
    mylite_storage_index_entryset *out_entries,
    unsigned long long *inout_appended_count,
    unsigned char *previous_page_bytes,
    mylite_storage_index_leaf_page *inout_previous_page,
    int *inout_has_previous_page
) {
    if (branch_page->table_id != table_id || branch_page->index_number != index_number) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (key_prefix_size > branch_page->key_size) {
        return MYLITE_STORAGE_OK;
    }

    unsigned long long first_child_page_id = 0ULL;
    mylite_storage_result result = find_index_branch_prefix_child_page(
        branch_page,
        key_prefix,
        key_prefix_size,
        &first_child_page_id
    );
    if (result == MYLITE_STORAGE_NOTFOUND) {
        return MYLITE_STORAGE_OK;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    size_t first_child_index = 0U;
    result = find_index_branch_child_offset(branch_page, first_child_page_id, &first_child_index);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    const size_t cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
    for (size_t i = first_child_index; i < branch_page->child_count; ++i) {
        const unsigned char *cell = branch_page->payload + (i * cell_size);
        const unsigned long long child_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        if (branch_page->level == 1U) {
            if (i == first_child_index) {
                result = append_index_branch_leaf_entries_from_prefix_to_entryset(
                    file,
                    filename,
                    header,
                    child_page_id,
                    table_id,
                    index_number,
                    branch_page->key_size,
                    key_prefix,
                    key_prefix_size,
                    out_entries,
                    inout_appended_count,
                    previous_page_bytes,
                    inout_previous_page,
                    inout_has_previous_page
                );
            } else {
                result = append_index_branch_leaf_entries_to_entryset(
                    file,
                    filename,
                    header,
                    child_page_id,
                    table_id,
                    index_number,
                    branch_page->key_size,
                    out_entries,
                    inout_appended_count,
                    previous_page_bytes,
                    inout_previous_page,
                    inout_has_previous_page
                );
            }
        } else {
            unsigned char child_page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
            mylite_storage_index_branch_page child_branch_page = {0};
            result = read_index_branch_child_page(
                file,
                filename,
                header,
                child_page_id,
                branch_page,
                table_id,
                index_number,
                &child_branch_page,
                child_page
            );
            if (result == MYLITE_STORAGE_OK) {
                result =
                    validate_index_branch_child_branch_fence(branch_page, i, &child_branch_page);
            }
            if (result == MYLITE_STORAGE_OK) {
                if (i == first_child_index) {
                    result = append_index_branch_entries_from_prefix_to_entryset(
                        file,
                        filename,
                        header,
                        &child_branch_page,
                        table_id,
                        index_number,
                        key_prefix,
                        key_prefix_size,
                        out_entries,
                        inout_appended_count,
                        previous_page_bytes,
                        inout_previous_page,
                        inout_has_previous_page
                    );
                } else {
                    result = append_index_branch_entries_to_entryset(
                        file,
                        filename,
                        header,
                        &child_branch_page,
                        table_id,
                        index_number,
                        out_entries,
                        inout_appended_count,
                        previous_page_bytes,
                        inout_previous_page,
                        inout_has_previous_page
                    );
                }
            }
        }
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
    }
    return MYLITE_STORAGE_OK;
}

