static mylite_storage_result find_index_leaf_exact_static_row_id(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    mylite_storage_statement *active_cache_statement,
    const mylite_storage_catalog_image *catalog,
    unsigned long long table_id,
    const char *schema_name,
    const char *table_name,
    unsigned index_number,
    const unsigned char *key,
    size_t key_size,
    unsigned long long *out_row_id,
    int *out_used_leaf
) {
    *out_row_id = 0ULL;
    *out_used_leaf = 0;

    mylite_storage_catalog_entry root_entry = {0};
    mylite_storage_result result = find_index_root_record_in_statement(
        active_cache_statement,
        header,
        catalog,
        schema_name,
        table_name,
        table_id,
        index_number,
        &root_entry
    );
    if (result == MYLITE_STORAGE_NOTFOUND) {
        return MYLITE_STORAGE_OK;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_index_leaf_page leaf_page = {0};
    mylite_storage_index_leaf_run leaf_run = {0};
    const mylite_storage_pager pager = open_storage_pager(file, filename, header);
    result = pager_read_page(&pager, root_entry.definition_root_page, page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (is_index_branch_page(page)) {
        mylite_storage_index_branch_page branch_page = {0};
        result =
            decode_index_branch_page(header, root_entry.definition_root_page, page, &branch_page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        return find_index_branch_exact_static_row_id(
            file,
            filename,
            header,
            root_entry.definition_root_page,
            &branch_page,
            table_id,
            index_number,
            key,
            key_size,
            out_row_id,
            out_used_leaf
        );
    }

    if (is_maintained_index_root_page(page)) {
        mylite_storage_maintained_index_root_page root_page = {0};
        result = decode_maintained_index_root_page(
            header,
            root_entry.definition_root_page,
            page,
            &root_page
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (root_page.table_id != table_id || root_page.index_number != index_number) {
            return MYLITE_STORAGE_CORRUPT;
        }
        unsigned long long tail_page_id = header->page_count;
        if (maintained_index_root_needs_tail_scan(&root_page)) {
            tail_page_id =
                maintained_index_root_tail_page_id(&root_page, root_entry.definition_root_page);
        }
        if (tail_page_id < header->page_count) {
            return MYLITE_STORAGE_OK;
        }

        maintained_index_root_page_as_leaf_page(&root_page, &leaf_page);
        *out_used_leaf = 1;
        find_index_leaf_page_first_match_row_id(&leaf_page, key, key_size, out_row_id);
        return MYLITE_STORAGE_OK;
    }

    result = decode_index_leaf_page(header, root_entry.definition_root_page, page, &leaf_page);
    if (result == MYLITE_STORAGE_NOTFOUND) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    store_durable_index_leaf_page(
        filename,
        header,
        root_entry.definition_root_page,
        page,
        &leaf_page
    );
    if (leaf_page.table_id != table_id || leaf_page.index_number != index_number) {
        return MYLITE_STORAGE_CORRUPT;
    }

    leaf_run = (mylite_storage_index_leaf_run){
        .first_page_id = root_entry.definition_root_page,
        .page_count = 1ULL,
        .entry_count = root_entry.definition_size,
        .key_size = leaf_page.key_size,
        .root_payload_offset = MYLITE_STORAGE_FORMAT_INDEX_LEAF_PAYLOAD_OFFSET,
    };
    if (root_entry.definition_size != 0ULL) {
        leaf_run.entry_capacity = index_leaf_entry_capacity(leaf_page.key_size);
        if (leaf_run.entry_capacity == 0U) {
            return MYLITE_STORAGE_CORRUPT;
        }
        leaf_run.page_count =
            ((root_entry.definition_size - 1ULL) / (unsigned long long)leaf_run.entry_capacity) +
            1ULL;
    }
    if (leaf_run.page_count == 0ULL ||
        leaf_run.page_count > header->page_count - root_entry.definition_root_page) {
        return MYLITE_STORAGE_CORRUPT;
    }
    leaf_run.tail_page_id = leaf_run.first_page_id + leaf_run.page_count;
    if (!index_leaf_run_page_entry_count_is_valid(&leaf_run, 0ULL, leaf_page.entry_count)) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (leaf_run.tail_page_id < header->page_count) {
        return MYLITE_STORAGE_OK;
    }

    *out_used_leaf = 1;
    return find_index_leaf_run_first_match_row_id(
        file,
        filename,
        header,
        &leaf_run,
        page,
        &leaf_page,
        table_id,
        index_number,
        key,
        key_size,
        out_row_id
    );
}

static mylite_storage_result find_index_branch_exact_static_row_id(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    unsigned long long root_page_id,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned index_number,
    const unsigned char *key,
    size_t key_size,
    unsigned long long *out_row_id,
    int *out_used_leaf
) {
    unsigned long long max_page_id = root_page_id;
    mylite_storage_result result = find_index_branch_max_page_id(
        file,
        filename,
        header,
        root_page_id,
        branch_page,
        table_id,
        index_number,
        &max_page_id
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (max_page_id == ULLONG_MAX || max_page_id >= header->page_count) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (max_page_id + 1ULL < header->page_count) {
        return MYLITE_STORAGE_OK;
    }

    *out_used_leaf = 1;
    if (key_size != branch_page->key_size) {
        return MYLITE_STORAGE_OK;
    }

    unsigned long long leaf_page_id = 0ULL;
    result = find_index_branch_leaf_page(
        file,
        filename,
        header,
        branch_page,
        table_id,
        index_number,
        key,
        key_size,
        0ULL,
        &leaf_page_id
    );
    if (result == MYLITE_STORAGE_NOTFOUND) {
        return MYLITE_STORAGE_OK;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_index_leaf_page leaf_page = {0};
    result = read_index_branch_leaf_page(file, filename, header, leaf_page_id, page, &leaf_page);
    if (result == MYLITE_STORAGE_NOTFOUND) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (leaf_page.table_id != table_id || leaf_page.index_number != index_number ||
        leaf_page.key_size != branch_page->key_size) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (compare_index_leaf_page_key_range(&leaf_page, key, key_size) == 0) {
        find_index_leaf_page_first_match_row_id(&leaf_page, key, key_size, out_row_id);
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result find_index_branch_max_page_id(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    unsigned long long branch_page_id,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned index_number,
    unsigned long long *inout_max_page_id
) {
    if (branch_page->table_id != table_id || branch_page->index_number != index_number ||
        branch_page->child_count == 0U) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (branch_page_id > *inout_max_page_id) {
        *inout_max_page_id = branch_page_id;
    }

    const size_t cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
    for (size_t i = 0U; i < branch_page->child_count; ++i) {
        const unsigned char *cell = branch_page->payload + (i * cell_size);
        const unsigned long long child_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        if (child_page_id > *inout_max_page_id) {
            *inout_max_page_id = child_page_id;
        }
    }
    if (branch_page->level == 1U) {
        return MYLITE_STORAGE_OK;
    }

    for (size_t i = 0U; i < branch_page->child_count; ++i) {
        const unsigned char *cell = branch_page->payload + (i * cell_size);
        const unsigned long long child_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        unsigned char child_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        mylite_storage_index_branch_page child_branch_page = {0};
        mylite_storage_result result = read_index_branch_child_page(
            file,
            filename,
            header,
            child_page_id,
            branch_page,
            table_id,
            index_number,
            &child_branch_page,
            child_page_bytes
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        result = validate_index_branch_child_branch_fence(branch_page, i, &child_branch_page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        result = find_index_branch_max_page_id(
            file,
            filename,
            header,
            child_page_id,
            &child_branch_page,
            table_id,
            index_number,
            inout_max_page_id
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result read_index_leaf_run_root(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    const mylite_storage_catalog_entry *root_entry,
    unsigned long long table_id,
    unsigned index_number,
    unsigned char *page,
    mylite_storage_index_leaf_page *out_index_leaf_page,
    mylite_storage_index_leaf_run *out_leaf_run
) {
    int used_cache = 0;
    mylite_storage_result result = MYLITE_STORAGE_OK;
    if (!statement_chain_has_deferred_durable_cache_retarget(
            active_statement_for(filename),
            table_id
        )) {
        result = read_cached_durable_index_leaf_page(
            filename,
            header,
            root_entry->definition_root_page,
            page,
            out_index_leaf_page,
            &used_cache
        );
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (!used_cache) {
        const mylite_storage_pager pager = open_storage_pager(file, filename, header);
        result = pager_read_page(&pager, root_entry->definition_root_page, page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (is_maintained_index_root_page(page)) {
            mylite_storage_maintained_index_root_page root_page = {0};
            result = decode_maintained_index_root_page(
                header,
                root_entry->definition_root_page,
                page,
                &root_page
            );
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }
            if (root_page.table_id != table_id || root_page.index_number != index_number) {
                return MYLITE_STORAGE_CORRUPT;
            }

            maintained_index_root_page_as_leaf_page(&root_page, out_index_leaf_page);
            unsigned long long tail_page_id = header->page_count;
            if (maintained_index_root_needs_tail_scan(&root_page)) {
                tail_page_id = maintained_index_root_tail_page_id(
                    &root_page,
                    root_entry->definition_root_page
                );
            }
            *out_leaf_run = (mylite_storage_index_leaf_run){
                .first_page_id = root_entry->definition_root_page,
                .page_count = 1ULL,
                .tail_page_id = tail_page_id,
                .entry_count = root_page.entry_count,
                .key_size = root_page.key_size,
                .entry_capacity = maintained_index_root_entry_capacity(root_page.key_size),
                .root_payload_offset = MYLITE_STORAGE_FORMAT_INDEX_ROOT_PAYLOAD_OFFSET,
            };
            return MYLITE_STORAGE_OK;
        }
        if (is_index_branch_page(page)) {
            mylite_storage_index_branch_page branch_page = {0};
            result = decode_index_branch_page(
                header,
                root_entry->definition_root_page,
                page,
                &branch_page
            );
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }
            return read_index_branch_leaf_run_root(
                file,
                filename,
                header,
                root_entry,
                table_id,
                index_number,
                &branch_page,
                page,
                out_index_leaf_page,
                out_leaf_run
            );
        }

        result = decode_index_leaf_page(
            header,
            root_entry->definition_root_page,
            page,
            out_index_leaf_page
        );
        if (result == MYLITE_STORAGE_OK) {
            store_durable_index_leaf_page(
                filename,
                header,
                root_entry->definition_root_page,
                page,
                out_index_leaf_page
            );
        }
    }
    if (result == MYLITE_STORAGE_NOTFOUND) {
        result = MYLITE_STORAGE_CORRUPT;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (out_index_leaf_page->table_id != table_id ||
        out_index_leaf_page->index_number != index_number) {
        return MYLITE_STORAGE_CORRUPT;
    }

    mylite_storage_index_leaf_run leaf_run = {
        .first_page_id = root_entry->definition_root_page,
        .page_count = 1ULL,
        .entry_count = root_entry->definition_size,
        .key_size = out_index_leaf_page->key_size,
        .root_payload_offset = MYLITE_STORAGE_FORMAT_INDEX_LEAF_PAYLOAD_OFFSET,
    };
    if (root_entry->definition_size != 0ULL) {
        leaf_run.entry_capacity = index_leaf_entry_capacity(out_index_leaf_page->key_size);
        if (leaf_run.entry_capacity == 0U) {
            return MYLITE_STORAGE_CORRUPT;
        }
        leaf_run.page_count =
            ((root_entry->definition_size - 1ULL) / (unsigned long long)leaf_run.entry_capacity) +
            1ULL;
    }
    if (leaf_run.page_count == 0ULL ||
        leaf_run.page_count > header->page_count - root_entry->definition_root_page) {
        return MYLITE_STORAGE_CORRUPT;
    }
    leaf_run.tail_page_id = leaf_run.first_page_id + leaf_run.page_count;

    if (!index_leaf_run_page_entry_count_is_valid(
            &leaf_run,
            0ULL,
            out_index_leaf_page->entry_count
        )) {
        return MYLITE_STORAGE_CORRUPT;
    }

    *out_leaf_run = leaf_run;
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result read_index_branch_leaf_run_root(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    const mylite_storage_catalog_entry *root_entry,
    unsigned long long table_id,
    unsigned index_number,
    const mylite_storage_index_branch_page *branch_page,
    unsigned char *page,
    mylite_storage_index_leaf_page *out_index_leaf_page,
    mylite_storage_index_leaf_run *out_leaf_run
) {
    const unsigned long long entry_count =
        branch_page->entry_count != 0ULL ? branch_page->entry_count : root_entry->definition_size;
    if (branch_page->table_id != table_id || branch_page->index_number != index_number ||
        branch_page->child_count == 0U || entry_count == 0ULL) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t entry_capacity = index_leaf_entry_capacity(branch_page->key_size);
    if (entry_capacity == 0U) {
        return MYLITE_STORAGE_CORRUPT;
    }

    mylite_storage_index_branch_leaf_collect collect = {0};
    initialize_index_branch_leaf_collect(&collect, root_entry->definition_root_page);
    mylite_storage_result result = collect_index_branch_leaf_run_pages(
        file,
        filename,
        header,
        root_entry->definition_root_page,
        branch_page,
        table_id,
        index_number,
        &collect
    );
    if (result != MYLITE_STORAGE_OK) {
        free_index_branch_leaf_collect(&collect);
        return result;
    }
    if (collect.max_page_id == ULLONG_MAX) {
        free_index_branch_leaf_collect(&collect);
        return MYLITE_STORAGE_CORRUPT;
    }

    if (collect.leaf_count == 0U) {
        free_index_branch_leaf_collect(&collect);
        return MYLITE_STORAGE_CORRUPT;
    }

    const unsigned long long first_child_page_id = collect.leaf_page_ids[0];
    result = read_index_branch_leaf_page(
        file,
        filename,
        header,
        first_child_page_id,
        page,
        out_index_leaf_page
    );
    if (result != MYLITE_STORAGE_OK) {
        free_index_branch_leaf_collect(&collect);
        return result;
    }
    if (out_index_leaf_page->table_id != table_id ||
        out_index_leaf_page->index_number != index_number ||
        out_index_leaf_page->key_size != branch_page->key_size) {
        free_index_branch_leaf_collect(&collect);
        return MYLITE_STORAGE_CORRUPT;
    }

    *out_leaf_run = (mylite_storage_index_leaf_run){
        .branch_root_page_id = root_entry->definition_root_page,
        .first_page_id = first_child_page_id,
        .page_count = (unsigned long long)collect.leaf_count,
        .tail_page_id = collect.max_page_id + 1ULL,
        .entry_count = entry_count,
        .branch_root_level = branch_page->level,
        .key_size = out_index_leaf_page->key_size,
        .entry_capacity = entry_capacity,
        .root_payload_offset = MYLITE_STORAGE_FORMAT_INDEX_LEAF_PAYLOAD_OFFSET,
    };
    result = assign_index_leaf_run_branch_child_page_ids(out_leaf_run, &collect);
    free_index_branch_leaf_collect(&collect);
    if (result != MYLITE_STORAGE_OK) {
        free_index_leaf_run(out_leaf_run);
        return result;
    }
    if (!index_leaf_run_page_entry_count_is_valid(
            out_leaf_run,
            0ULL,
            out_index_leaf_page->entry_count
        )) {
        free_index_leaf_run(out_leaf_run);
        return MYLITE_STORAGE_CORRUPT;
    }

    store_durable_index_leaf_page(filename, header, first_child_page_id, page, out_index_leaf_page);
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result collect_index_branch_leaf_run_pages(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    unsigned long long branch_page_id,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned index_number,
    mylite_storage_index_branch_leaf_collect *collect
) {
    if (branch_page->table_id != table_id || branch_page->index_number != index_number ||
        branch_page->child_count == 0U) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (branch_page_id > collect->max_page_id) {
        collect->max_page_id = branch_page_id;
    }
    if (branch_page->level > 1U) {
        return collect_index_branch_leaf_run_child_branch_pages(
            file,
            filename,
            header,
            branch_page,
            table_id,
            index_number,
            collect
        );
    }

    const size_t cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
    for (size_t i = 0U; i < branch_page->child_count; ++i) {
        const unsigned char *cell = branch_page->payload + (i * cell_size);
        const unsigned long long child_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        const mylite_storage_result result =
            append_index_branch_leaf_collect_page(collect, child_page_id);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result collect_index_branch_leaf_run_child_branch_pages(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned index_number,
    mylite_storage_index_branch_leaf_collect *collect
) {
    const size_t cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
    for (size_t i = 0U; i < branch_page->child_count; ++i) {
        const unsigned char *cell = branch_page->payload + (i * cell_size);
        const unsigned long long child_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        unsigned char child_page_bytes[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        mylite_storage_index_branch_page child_branch_page = {0};
        mylite_storage_result result = read_index_branch_child_page(
            file,
            filename,
            header,
            child_page_id,
            branch_page,
            table_id,
            index_number,
            &child_branch_page,
            child_page_bytes
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        result = validate_index_branch_child_branch_fence(branch_page, i, &child_branch_page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        result = collect_index_branch_leaf_run_pages(
            file,
            filename,
            header,
            child_page_id,
            &child_branch_page,
            table_id,
            index_number,
            collect
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
    }
    return MYLITE_STORAGE_OK;
}

static void initialize_index_branch_leaf_collect(
    mylite_storage_index_branch_leaf_collect *collect,
    unsigned long long max_page_id
) {
    *collect = (mylite_storage_index_branch_leaf_collect){0};
    collect->leaf_page_ids = collect->inline_leaf_page_ids;
    collect->leaf_capacity = MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN;
    collect->max_page_id = max_page_id;
}

static mylite_storage_result append_index_branch_leaf_collect_page(
    mylite_storage_index_branch_leaf_collect *collect,
    unsigned long long leaf_page_id
) {
    if (collect->leaf_count == collect->leaf_capacity) {
        if (collect->leaf_capacity > SIZE_MAX / (2U * sizeof(*collect->leaf_page_ids))) {
            return MYLITE_STORAGE_FULL;
        }
        const size_t new_capacity = collect->leaf_capacity * 2U;
        unsigned long long *new_leaf_page_ids = NULL;
        if (collect->leaf_page_ids == collect->inline_leaf_page_ids) {
            new_leaf_page_ids =
                (unsigned long long *)malloc(new_capacity * sizeof(*new_leaf_page_ids));
            if (new_leaf_page_ids == NULL) {
                return MYLITE_STORAGE_NOMEM;
            }
            memcpy(
                new_leaf_page_ids,
                collect->inline_leaf_page_ids,
                collect->leaf_count * sizeof(*new_leaf_page_ids)
            );
        } else {
            new_leaf_page_ids = (unsigned long long *)
                realloc(collect->leaf_page_ids, new_capacity * sizeof(*new_leaf_page_ids));
            if (new_leaf_page_ids == NULL) {
                return MYLITE_STORAGE_NOMEM;
            }
        }
        collect->leaf_page_ids = new_leaf_page_ids;
        collect->leaf_capacity = new_capacity;
    }

    collect->leaf_page_ids[collect->leaf_count++] = leaf_page_id;
    if (leaf_page_id > collect->max_page_id) {
        collect->max_page_id = leaf_page_id;
    }
    return MYLITE_STORAGE_OK;
}

static void free_index_branch_leaf_collect(mylite_storage_index_branch_leaf_collect *collect) {
    if (collect->leaf_page_ids != NULL && collect->leaf_page_ids != collect->inline_leaf_page_ids) {
        free(collect->leaf_page_ids);
    }
    *collect = (mylite_storage_index_branch_leaf_collect){0};
}

static mylite_storage_result assign_index_leaf_run_branch_child_page_ids(
    mylite_storage_index_leaf_run *leaf_run,
    const mylite_storage_index_branch_leaf_collect *collect
) {
    if (collect->leaf_count == 0U) {
        return MYLITE_STORAGE_CORRUPT;
    }

    leaf_run->branch_child_page_id_count = collect->leaf_count;
    if (collect->leaf_count <= MYLITE_STORAGE_INDEX_BRANCH_MAX_CHILDREN) {
        leaf_run->branch_child_page_ids = leaf_run->inline_branch_child_page_ids;
    } else {
        if (collect->leaf_count > SIZE_MAX / sizeof(*leaf_run->branch_child_page_ids)) {
            return MYLITE_STORAGE_FULL;
        }
        leaf_run->branch_child_page_ids = (unsigned long long *)malloc(
            collect->leaf_count * sizeof(*leaf_run->branch_child_page_ids)
        );
        if (leaf_run->branch_child_page_ids == NULL) {
            return MYLITE_STORAGE_NOMEM;
        }
    }
    memcpy(
        leaf_run->branch_child_page_ids,
        collect->leaf_page_ids,
        collect->leaf_count * sizeof(*leaf_run->branch_child_page_ids)
    );
    return MYLITE_STORAGE_OK;
}

static void free_index_leaf_run(mylite_storage_index_leaf_run *leaf_run) {
    if (leaf_run->branch_child_page_ids != NULL &&
        leaf_run->branch_child_page_ids != leaf_run->inline_branch_child_page_ids) {
        free(leaf_run->branch_child_page_ids);
    }
    *leaf_run = (mylite_storage_index_leaf_run){0};
}

static mylite_storage_result read_index_branch_child_page(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    unsigned long long child_page_id,
    const mylite_storage_index_branch_page *parent_branch_page,
    unsigned long long table_id,
    unsigned index_number,
    mylite_storage_index_branch_page *out_child_branch_page,
    unsigned char *out_child_page
) {
    int used_active_branch_cache = 0;
    int can_store_active_branch_cache = 0;
    mylite_storage_result result = read_cached_active_index_branch_page(
        file,
        header,
        child_page_id,
        out_child_page,
        out_child_branch_page,
        &used_active_branch_cache
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (!used_active_branch_cache) {
        can_store_active_branch_cache =
            active_index_branch_page_cache_statement_for_file(file) != NULL;
        const mylite_storage_pager pager = open_storage_pager(file, filename, header);
        result = pager_read_page(&pager, child_page_id, out_child_page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
#ifdef MYLITE_STORAGE_TEST_HOOKS
        if (can_store_active_branch_cache) {
            ++test_active_branch_page_plan_read_count;
        }
#endif
        result =
            decode_index_branch_page(header, child_page_id, out_child_page, out_child_branch_page);
        if (result != MYLITE_STORAGE_OK) {
            return result == MYLITE_STORAGE_NOTFOUND ? MYLITE_STORAGE_CORRUPT : result;
        }
    }
    if (out_child_branch_page->table_id != table_id ||
        out_child_branch_page->index_number != index_number ||
        out_child_branch_page->key_size != parent_branch_page->key_size ||
        parent_branch_page->level <= 1U ||
        out_child_branch_page->level != parent_branch_page->level - 1U) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (!used_active_branch_cache && can_store_active_branch_cache) {
        store_active_index_branch_page_for_file(
            file,
            child_page_id,
            out_child_page,
            out_child_branch_page
        );
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result validate_index_branch_child_branch_fence(
    const mylite_storage_index_branch_page *parent_branch_page,
    size_t child_index,
    const mylite_storage_index_branch_page *child_branch_page
) {
    if (child_index >= parent_branch_page->child_count || child_branch_page->child_count == 0U) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + parent_branch_page->key_size;
    const unsigned char *parent_cell = parent_branch_page->payload + (child_index * cell_size);
    const unsigned char *child_cell =
        child_branch_page->payload + ((child_branch_page->child_count - 1U) * cell_size);
    if (memcmp(
            parent_cell + MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_MAX_KEY_OFFSET,
            child_cell + MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_MAX_KEY_OFFSET,
            parent_branch_page->key_size
        ) != 0 ||
        get_u64_le(parent_cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_MAX_ROW_ID_OFFSET) !=
            get_u64_le(child_cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_MAX_ROW_ID_OFFSET)) {
        return MYLITE_STORAGE_CORRUPT;
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result read_index_leaf_run_page(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    const mylite_storage_index_leaf_run *leaf_run,
    unsigned long long table_id,
    unsigned index_number,
    unsigned long long page_offset,
    unsigned char *page,
    mylite_storage_index_leaf_page *out_index_leaf_page
) {
    if (page_offset >= leaf_run->page_count) {
        return MYLITE_STORAGE_CORRUPT;
    }

    unsigned long long page_id = leaf_run->first_page_id + page_offset;
    if (leaf_run->branch_root_page_id != 0ULL) {
        if (page_offset >= (unsigned long long)leaf_run->branch_child_page_id_count) {
            return MYLITE_STORAGE_CORRUPT;
        }
        page_id = leaf_run->branch_child_page_ids[(size_t)page_offset];
        if (page_id == 0ULL) {
            return MYLITE_STORAGE_CORRUPT;
        }
    }

    mylite_storage_result result = MYLITE_STORAGE_OK;
    if (leaf_run->branch_root_page_id != 0ULL) {
        result =
            read_index_branch_leaf_page(file, filename, header, page_id, page, out_index_leaf_page);
    } else {
        result = read_index_leaf_page(file, filename, header, page_id, page, out_index_leaf_page);
    }
    if (result == MYLITE_STORAGE_NOTFOUND) {
        result = MYLITE_STORAGE_CORRUPT;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (out_index_leaf_page->table_id != table_id ||
        out_index_leaf_page->index_number != index_number ||
        out_index_leaf_page->key_size != leaf_run->key_size ||
        !index_leaf_run_page_entry_count_is_valid(
            leaf_run,
            page_offset,
            out_index_leaf_page->entry_count
        )) {
        return MYLITE_STORAGE_CORRUPT;
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result read_index_leaf_run_page_or_root(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    const mylite_storage_index_leaf_run *leaf_run,
    const unsigned char *root_page,
    const mylite_storage_index_leaf_page *root_leaf_page,
    unsigned long long table_id,
    unsigned index_number,
    unsigned long long page_offset,
    unsigned char *page,
    mylite_storage_index_leaf_page *out_index_leaf_page
) {
    if (page_offset >= leaf_run->page_count) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (page_offset == 0ULL && root_page != NULL && root_leaf_page != NULL) {
        memcpy(page, root_page, MYLITE_STORAGE_FORMAT_PAGE_SIZE);
        *out_index_leaf_page = *root_leaf_page;
        out_index_leaf_page->payload = page + leaf_run->root_payload_offset;
        return MYLITE_STORAGE_OK;
    }

    return read_index_leaf_run_page(
        file,
        filename,
        header,
        leaf_run,
        table_id,
        index_number,
        page_offset,
        page,
        out_index_leaf_page
    );
}

static mylite_storage_result find_static_index_leaf_prefix_exists(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    mylite_storage_statement *active_cache_statement,
    const mylite_storage_catalog_image *catalog,
    unsigned long long table_id,
    const char *schema_name,
    const char *table_name,
    unsigned index_number,
    const unsigned char *key_prefix,
    size_t key_prefix_size,
    unsigned long long skip_row_id,
    int *out_exists,
    int *out_used_leaf
) {
    *out_exists = 0;
    *out_used_leaf = 0;

    mylite_storage_catalog_entry root_entry = {0};
    mylite_storage_result result = find_index_root_record_in_statement(
        active_cache_statement,
        header,
        catalog,
        schema_name,
        table_name,
        table_id,
        index_number,
        &root_entry
    );
    if (result == MYLITE_STORAGE_NOTFOUND) {
        return MYLITE_STORAGE_OK;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    const mylite_storage_pager pager = open_storage_pager(file, filename, header);
    result = pager_read_page(&pager, root_entry.definition_root_page, page);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (is_index_branch_page(page)) {
        mylite_storage_index_branch_page branch_page = {0};
        result =
            decode_index_branch_page(header, root_entry.definition_root_page, page, &branch_page);
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        result = find_static_index_branch_prefix_exists(
            file,
            filename,
            header,
            root_entry.definition_root_page,
            &branch_page,
            table_id,
            index_number,
            key_prefix,
            key_prefix_size,
            skip_row_id,
            out_exists,
            out_used_leaf
        );
        if (result != MYLITE_STORAGE_OK || *out_used_leaf) {
            return result;
        }
    }

    mylite_storage_index_leaf_page leaf_page = {0};
    mylite_storage_index_leaf_run leaf_run = {0};
    result = read_index_leaf_run_root(
        file,
        filename,
        header,
        &root_entry,
        table_id,
        index_number,
        page,
        &leaf_page,
        &leaf_run
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (leaf_run.tail_page_id < header->page_count) {
        free_index_leaf_run(&leaf_run);
        return MYLITE_STORAGE_OK;
    }

    *out_used_leaf = 1;
    result = scan_static_index_leaf_prefix_exists(
        file,
        filename,
        header,
        &leaf_run,
        page,
        &leaf_page,
        table_id,
        index_number,
        key_prefix,
        key_prefix_size,
        skip_row_id,
        out_exists
    );
    free_index_leaf_run(&leaf_run);
    return result;
}

static mylite_storage_result find_static_index_branch_prefix_exists(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    unsigned long long root_page_id,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned index_number,
    const unsigned char *key_prefix,
    size_t key_prefix_size,
    unsigned long long skip_row_id,
    int *out_exists,
    int *out_used_leaf
) {
    unsigned long long max_page_id = root_page_id;
    mylite_storage_result result = find_index_branch_max_page_id(
        file,
        filename,
        header,
        root_page_id,
        branch_page,
        table_id,
        index_number,
        &max_page_id
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (max_page_id == ULLONG_MAX || max_page_id >= header->page_count) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (max_page_id + 1ULL < header->page_count) {
        return MYLITE_STORAGE_OK;
    }

    *out_used_leaf = 1;
    if (key_prefix_size > branch_page->key_size) {
        return MYLITE_STORAGE_OK;
    }

    int past_prefix = 0;
    return scan_index_branch_prefix_exists(
        file,
        filename,
        header,
        branch_page,
        table_id,
        index_number,
        key_prefix,
        key_prefix_size,
        skip_row_id,
        out_exists,
        &past_prefix
    );
}

static mylite_storage_result scan_index_branch_prefix_exists(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    const mylite_storage_index_branch_page *branch_page,
    unsigned long long table_id,
    unsigned index_number,
    const unsigned char *key_prefix,
    size_t key_prefix_size,
    unsigned long long skip_row_id,
    int *out_exists,
    int *out_past_prefix
) {
    *out_past_prefix = 0;
    if (branch_page->table_id != table_id || branch_page->index_number != index_number) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (key_prefix_size > branch_page->key_size) {
        *out_past_prefix = 1;
        return MYLITE_STORAGE_OK;
    }

    unsigned long long first_child_page_id = 0ULL;
    mylite_storage_result result = find_index_branch_prefix_child_page(
        branch_page,
        key_prefix,
        key_prefix_size,
        &first_child_page_id
    );
    if (result == MYLITE_STORAGE_NOTFOUND) {
        *out_past_prefix = 1;
        return MYLITE_STORAGE_OK;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    size_t first_child_index = 0U;
    result = find_index_branch_child_offset(branch_page, first_child_page_id, &first_child_index);
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    const size_t cell_size =
        MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_HEADER_SIZE + branch_page->key_size;
    for (size_t i = first_child_index; i < branch_page->child_count; ++i) {
        const unsigned char *cell = branch_page->payload + (i * cell_size);
        const unsigned long long child_page_id =
            get_u64_le(cell, MYLITE_STORAGE_FORMAT_INDEX_BRANCH_CELL_CHILD_PAGE_ID_OFFSET);
        if (branch_page->level == 1U) {
            result = scan_index_branch_leaf_prefix_exists(
                file,
                filename,
                header,
                child_page_id,
                table_id,
                index_number,
                branch_page->key_size,
                key_prefix,
                key_prefix_size,
                skip_row_id,
                out_exists,
                out_past_prefix
            );
        } else {
            unsigned char child_page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
            mylite_storage_index_branch_page child_branch_page = {0};
            result = read_index_branch_child_page(
                file,
                filename,
                header,
                child_page_id,
                branch_page,
                table_id,
                index_number,
                &child_branch_page,
                child_page
            );
            if (result == MYLITE_STORAGE_OK) {
                result =
                    validate_index_branch_child_branch_fence(branch_page, i, &child_branch_page);
            }
            if (result == MYLITE_STORAGE_OK) {
                result = scan_index_branch_prefix_exists(
                    file,
                    filename,
                    header,
                    &child_branch_page,
                    table_id,
                    index_number,
                    key_prefix,
                    key_prefix_size,
                    skip_row_id,
                    out_exists,
                    out_past_prefix
                );
            }
        }
        if (result != MYLITE_STORAGE_OK || *out_exists || *out_past_prefix) {
            return result;
        }
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result scan_index_branch_leaf_prefix_exists(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    unsigned long long leaf_page_id,
    unsigned long long table_id,
    unsigned index_number,
    size_t key_size,
    const unsigned char *key_prefix,
    size_t key_prefix_size,
    unsigned long long skip_row_id,
    int *out_exists,
    int *out_past_prefix
) {
    *out_past_prefix = 0;

    unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_index_leaf_page leaf_page = {0};
    mylite_storage_result result =
        read_index_branch_leaf_page(file, filename, header, leaf_page_id, page, &leaf_page);
    if (result == MYLITE_STORAGE_NOTFOUND) {
        return MYLITE_STORAGE_CORRUPT;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }
    if (leaf_page.table_id != table_id || leaf_page.index_number != index_number ||
        leaf_page.key_size != key_size) {
        return MYLITE_STORAGE_CORRUPT;
    }

    const size_t first_candidate =
        find_index_leaf_page_prefix_lower_bound(&leaf_page, key_prefix, key_prefix_size);
    for (size_t i = first_candidate; i < leaf_page.entry_count; ++i) {
        const int key_cmp = compare_leaf_key_prefix(&leaf_page, i, key_prefix, key_prefix_size);
        if (key_cmp < 0) {
            return MYLITE_STORAGE_CORRUPT;
        }
        if (key_cmp > 0) {
            *out_past_prefix = 1;
            return MYLITE_STORAGE_OK;
        }
        const unsigned long long row_id = index_leaf_entry_row_id(&leaf_page, i);
        if (skip_row_id != 0ULL && row_id == skip_row_id) {
            continue;
        }
        *out_exists = 1;
        (void)mark_active_live_row(file, header, table_id, row_id);
        return MYLITE_STORAGE_OK;
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result find_overlay_index_leaf_prefix_exists(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    mylite_storage_statement *active_cache_statement,
    const mylite_storage_catalog_image *catalog,
    unsigned long long table_id,
    const char *schema_name,
    const char *table_name,
    unsigned index_number,
    const unsigned char *key_prefix,
    size_t key_prefix_size,
    unsigned long long skip_row_id,
    int *out_exists,
    int *out_used_leaf
) {
    *out_exists = 0;
    *out_used_leaf = 0;

    mylite_storage_catalog_entry root_entry = {0};
    mylite_storage_result result = find_index_root_record_in_statement(
        active_cache_statement,
        header,
        catalog,
        schema_name,
        table_name,
        table_id,
        index_number,
        &root_entry
    );
    if (result == MYLITE_STORAGE_NOTFOUND) {
        return MYLITE_STORAGE_OK;
    }
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_index_leaf_page leaf_page = {0};
    mylite_storage_index_leaf_run leaf_run = {0};
    result = read_index_leaf_run_root(
        file,
        filename,
        header,
        &root_entry,
        table_id,
        index_number,
        page,
        &leaf_page,
        &leaf_run
    );
    if (result != MYLITE_STORAGE_OK) {
        return result;
    }

    *out_used_leaf = 1;
    mylite_storage_live_row_id_set row_ids = {0};
    result = append_index_leaf_run_prefix_row_ids_to_set(
        file,
        filename,
        header,
        &leaf_run,
        page,
        &leaf_page,
        table_id,
        index_number,
        key_prefix,
        key_prefix_size,
        &row_ids
    );
    if (result == MYLITE_STORAGE_OK && leaf_run.tail_page_id < header->page_count) {
        result = scan_index_prefix_exists_from(
            file,
            header,
            table_id,
            index_number,
            key_prefix,
            key_prefix_size,
            leaf_run.tail_page_id,
            &row_ids
        );
    }
    if (result == MYLITE_STORAGE_OK) {
        *out_exists = live_row_id_set_contains_any_except(&row_ids, skip_row_id);
    }
    free_live_row_id_set(&row_ids);
    free_index_leaf_run(&leaf_run);
    return result;
}

static mylite_storage_result scan_static_index_leaf_prefix_exists(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    const mylite_storage_index_leaf_run *leaf_run,
    const unsigned char *root_page,
    const mylite_storage_index_leaf_page *root_leaf_page,
    unsigned long long table_id,
    unsigned index_number,
    const unsigned char *key_prefix,
    size_t key_prefix_size,
    unsigned long long skip_row_id,
    int *out_exists
) {
    *out_exists = 0;

    unsigned long long first_page_offset = 0ULL;
    int can_match = 0;
    mylite_storage_result result = find_index_leaf_run_prefix_lower_page(
        file,
        filename,
        header,
        leaf_run,
        root_page,
        root_leaf_page,
        table_id,
        index_number,
        key_prefix,
        key_prefix_size,
        &first_page_offset,
        &can_match
    );
    if (result != MYLITE_STORAGE_OK || !can_match) {
        return result;
    }

    unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
    mylite_storage_index_leaf_page leaf_page = {0};
    for (unsigned long long page_offset = first_page_offset; page_offset < leaf_run->page_count;
         ++page_offset) {
        result = read_index_leaf_run_page_or_root(
            file,
            filename,
            header,
            leaf_run,
            root_page,
            root_leaf_page,
            table_id,
            index_number,
            page_offset,
            page,
            &leaf_page
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (leaf_page.key_size < key_prefix_size) {
            return MYLITE_STORAGE_OK;
        }
        const size_t first_candidate =
            find_index_leaf_page_prefix_lower_bound(&leaf_page, key_prefix, key_prefix_size);
        for (size_t i = first_candidate; i < leaf_page.entry_count; ++i) {
            const int key_cmp = compare_leaf_key_prefix(&leaf_page, i, key_prefix, key_prefix_size);
            if (key_cmp < 0) {
                return MYLITE_STORAGE_CORRUPT;
            }
            if (key_cmp > 0) {
                return MYLITE_STORAGE_OK;
            }
            const unsigned long long row_id = index_leaf_entry_row_id(&leaf_page, i);
            if (skip_row_id != 0ULL && row_id == skip_row_id) {
                continue;
            }
            *out_exists = 1;
            (void)mark_active_live_row(file, header, table_id, row_id);
            return MYLITE_STORAGE_OK;
        }
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_index_leaf_run_prefix_row_ids_to_set(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    const mylite_storage_index_leaf_run *leaf_run,
    const unsigned char *root_page,
    const mylite_storage_index_leaf_page *root_leaf_page,
    unsigned long long table_id,
    unsigned index_number,
    const unsigned char *key_prefix,
    size_t key_prefix_size,
    mylite_storage_live_row_id_set *row_ids
) {
    unsigned long long first_page_offset = 0ULL;
    int can_match = 0;
    mylite_storage_result result = find_index_leaf_run_prefix_lower_page(
        file,
        filename,
        header,
        leaf_run,
        root_page,
        root_leaf_page,
        table_id,
        index_number,
        key_prefix,
        key_prefix_size,
        &first_page_offset,
        &can_match
    );
    if (result != MYLITE_STORAGE_OK || !can_match) {
        return result;
    }

    for (unsigned long long page_offset = first_page_offset; page_offset < leaf_run->page_count;
         ++page_offset) {
        unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        mylite_storage_index_leaf_page leaf_page = {0};
        result = read_index_leaf_run_page_or_root(
            file,
            filename,
            header,
            leaf_run,
            root_page,
            root_leaf_page,
            table_id,
            index_number,
            page_offset,
            page,
            &leaf_page
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }

        int past_prefix = 0;
        result = append_index_leaf_prefix_row_ids_to_set(
            &leaf_page,
            key_prefix,
            key_prefix_size,
            row_ids,
            &past_prefix
        );
        if (result != MYLITE_STORAGE_OK || past_prefix) {
            return result;
        }
    }
    return MYLITE_STORAGE_OK;
}

static mylite_storage_result append_index_leaf_prefix_row_ids_to_set(
    const mylite_storage_index_leaf_page *leaf_page,
    const unsigned char *key_prefix,
    size_t key_prefix_size,
    mylite_storage_live_row_id_set *row_ids,
    int *out_past_prefix
) {
    *out_past_prefix = 0;
    if (leaf_page->key_size < key_prefix_size) {
        *out_past_prefix = 1;
        return MYLITE_STORAGE_OK;
    }

    const size_t lower =
        find_index_leaf_page_prefix_lower_bound(leaf_page, key_prefix, key_prefix_size);
    for (size_t i = lower; i < leaf_page->entry_count; ++i) {
        const int key_cmp = compare_leaf_key_prefix(leaf_page, i, key_prefix, key_prefix_size);
        if (key_cmp < 0) {
            return MYLITE_STORAGE_CORRUPT;
        }
        if (key_cmp > 0) {
            *out_past_prefix = 1;
            return MYLITE_STORAGE_OK;
        }
        const mylite_storage_result result =
            add_live_row_id_to_set(row_ids, index_leaf_entry_row_id(leaf_page, i));
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
    }
    return MYLITE_STORAGE_OK;
}

static size_t find_index_leaf_page_prefix_lower_bound(
    const mylite_storage_index_leaf_page *leaf_page,
    const unsigned char *key_prefix,
    size_t key_prefix_size
) {
    size_t lower = 0U;
    size_t upper = leaf_page->entry_count;
    while (lower < upper) {
        const size_t mid = lower + ((upper - lower) / 2U);
        if (compare_leaf_key_prefix(leaf_page, mid, key_prefix, key_prefix_size) < 0) {
            lower = mid + 1U;
        } else {
            upper = mid;
        }
    }
    return lower;
}

static int compare_leaf_key_prefix(
    const mylite_storage_index_leaf_page *leaf_page,
    size_t entry_index,
    const unsigned char *key_prefix,
    size_t key_prefix_size
) {
    return memcmp(index_leaf_entry_key(leaf_page, entry_index), key_prefix, key_prefix_size);
}

static size_t index_leaf_run_expected_entry_count(
    const mylite_storage_index_leaf_run *leaf_run,
    unsigned long long page_offset
) {
    if (leaf_run->entry_count == 0ULL) {
        return 0U;
    }
    if (page_offset + 1ULL < leaf_run->page_count) {
        return leaf_run->entry_capacity;
    }
    return (size_t)(leaf_run->entry_count -
                    (page_offset * (unsigned long long)leaf_run->entry_capacity));
}

static int index_leaf_run_page_entry_count_is_valid(
    const mylite_storage_index_leaf_run *leaf_run,
    unsigned long long page_offset,
    size_t entry_count
) {
    if (leaf_run->branch_root_page_id != 0ULL) {
        return entry_count != 0U && entry_count <= leaf_run->entry_capacity;
    }
    return entry_count == index_leaf_run_expected_entry_count(leaf_run, page_offset);
}

static mylite_storage_result append_index_leaf_run_matches_to_row_id_list(
    FILE *file,
    const char *filename,
    const mylite_storage_header *header,
    const mylite_storage_index_leaf_run *leaf_run,
    const unsigned char *root_page,
    const mylite_storage_index_leaf_page *root_leaf_page,
    unsigned long long table_id,
    unsigned index_number,
    const unsigned char *key,
    size_t key_size,
    mylite_storage_row_id_list *out_row_ids
) {
    unsigned long long match_page_offset = 0ULL;
    int found = 0;
    mylite_storage_result result = find_index_leaf_run_match_page(
        file,
        filename,
        header,
        leaf_run,
        root_page,
        root_leaf_page,
        table_id,
        index_number,
        key,
        key_size,
        &match_page_offset,
        &found
    );
    if (result != MYLITE_STORAGE_OK || !found) {
        return result;
    }

    unsigned long long first_match_page_offset = match_page_offset;
    while (first_match_page_offset > 0ULL) {
        unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        mylite_storage_index_leaf_page leaf_page = {0};
        result = read_index_leaf_run_page_or_root(
            file,
            filename,
            header,
            leaf_run,
            root_page,
            root_leaf_page,
            table_id,
            index_number,
            first_match_page_offset - 1ULL,
            page,
            &leaf_page
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }
        if (!index_leaf_page_last_key_matches(&leaf_page, key, key_size)) {
            break;
        }
        --first_match_page_offset;
    }

    for (unsigned long long page_offset = first_match_page_offset;
         page_offset < leaf_run->page_count;
         ++page_offset) {
        unsigned char page[MYLITE_STORAGE_FORMAT_PAGE_SIZE];
        mylite_storage_index_leaf_page leaf_page = {0};
        result = read_index_leaf_run_page_or_root(
            file,
            filename,
            header,
            leaf_run,
            root_page,
            root_leaf_page,
            table_id,
            index_number,
            page_offset,
            page,
            &leaf_page
        );
        if (result != MYLITE_STORAGE_OK) {
            return result;
        }

        const int range_cmp = compare_index_leaf_page_key_range(&leaf_page, key, key_size);
        if (range_cmp < 0) {
            break;
        }
        if (range_cmp > 0 || (page_offset != first_match_page_offset &&
                              !index_leaf_page_first_key_matches(&leaf_page, key, key_size))) {
            return MYLITE_STORAGE_CORRUPT;
        }
        if (range_cmp == 0) {
            result =
                append_index_leaf_matches_to_row_id_list(&leaf_page, key, key_size, out_row_ids);
            if (result != MYLITE_STORAGE_OK) {
                return result;
            }
        }
        if (!index_leaf_page_last_key_matches(&leaf_page, key, key_size)) {
            break;
        }
    }
    return MYLITE_STORAGE_OK;
}

